import React, { useState } from 'react';

const VIEW_ICON = '▤';

export default function ViewSidebar({ views, activeViewId, onSwitch, onCreate, onRename, onDelete }) {
  const [creatingNew, setCreatingNew] = useState(false);
  const [newViewName, setNewViewName] = useState('');
  const [renamingId, setRenamingId] = useState(null);
  const [renameValue, setRenameValue] = useState('');
  const [hoveredId, setHoveredId] = useState(null);

  async function handleCreate() {
    const name = newViewName.trim();
    if (!name) return;
    await onCreate(name);
    setCreatingNew(false);
    setNewViewName('');
  }

  async function handleRename(viewId) {
    const name = renameValue.trim();
    if (!name) { setRenamingId(null); return; }
    await onRename(viewId, name);
    setRenamingId(null);
  }

  function startRename(view) {
    setRenamingId(view.id);
    setRenameValue(view.name);
  }

  return (
    <div style={styles.sidebar}>
      <div style={styles.sidebarHeader}>Views</div>

      {views.map((view) => {
        const isActive = view.id === activeViewId;
        const isRenaming = renamingId === view.id;

        return (
          <div
            key={view.id}
            style={{
              ...styles.viewItem,
              background: isActive ? '#DEEBFF' : hoveredId === view.id ? '#F4F5F7' : 'transparent',
              color: isActive ? '#0052CC' : '#172B4D',
            }}
            onMouseEnter={() => setHoveredId(view.id)}
            onMouseLeave={() => setHoveredId(null)}
          >
            {isRenaming ? (
              <input
                autoFocus
                style={styles.renameInput}
                value={renameValue}
                onChange={(e) => setRenameValue(e.target.value)}
                onBlur={() => handleRename(view.id)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleRename(view.id);
                  if (e.key === 'Escape') setRenamingId(null);
                }}
              />
            ) : (
              <>
                <span
                  style={styles.viewIcon}
                  title={isActive ? 'Active view' : ''}
                >
                  {VIEW_ICON}
                </span>
                <span
                  style={styles.viewName}
                  onClick={() => onSwitch(view.id)}
                  onDoubleClick={() => startRename(view)}
                  title="Double-click to rename"
                >
                  {view.name}
                </span>
                {hoveredId === view.id && (
                  <div style={styles.viewActions}>
                    <button
                      style={styles.actionBtn}
                      title="Rename"
                      onClick={(e) => { e.stopPropagation(); startRename(view); }}
                    >
                      ✏
                    </button>
                    {views.length > 1 && (
                      <button
                        style={{ ...styles.actionBtn, color: '#DE350B' }}
                        title="Delete view"
                        onClick={(e) => {
                          e.stopPropagation();
                          if (window.confirm(`Delete view "${view.name}"?`)) {
                            onDelete(view.id);
                          }
                        }}
                      >
                        🗑
                      </button>
                    )}
                  </div>
                )}
              </>
            )}
          </div>
        );
      })}

      <div style={styles.divider} />

      {creatingNew ? (
        <div style={styles.newViewForm}>
          <input
            autoFocus
            style={styles.newViewInput}
            placeholder="View name…"
            value={newViewName}
            onChange={(e) => setNewViewName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleCreate();
              if (e.key === 'Escape') { setCreatingNew(false); setNewViewName(''); }
            }}
          />
          <button style={styles.createConfirmBtn} onClick={handleCreate}>Create</button>
          <button style={styles.createCancelBtn} onClick={() => { setCreatingNew(false); setNewViewName(''); }}>✕</button>
        </div>
      ) : (
        <button style={styles.createViewBtn} onClick={() => setCreatingNew(true)}>
          + Create view
        </button>
      )}
    </div>
  );
}

const styles = {
  sidebar: {
    width: '200px',
    flexShrink: 0,
    background: '#fff',
    borderRight: '1px solid #DFE1E6',
    display: 'flex',
    flexDirection: 'column',
    overflowY: 'auto',
    paddingTop: '8px',
    paddingBottom: '8px',
  },
  sidebarHeader: {
    fontSize: '11px',
    fontWeight: 700,
    color: '#6B778C',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
    padding: '4px 12px 8px',
  },
  viewItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '6px',
    padding: '6px 10px',
    cursor: 'pointer',
    borderRadius: '4px',
    margin: '1px 4px',
    position: 'relative',
    minHeight: '30px',
  },
  viewIcon: {
    fontSize: '13px',
    flexShrink: 0,
    opacity: 0.7,
  },
  viewName: {
    fontSize: '13px',
    fontWeight: 500,
    flex: 1,
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap',
  },
  viewActions: {
    display: 'flex',
    gap: '2px',
    flexShrink: 0,
  },
  actionBtn: {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    fontSize: '11px',
    padding: '2px 4px',
    borderRadius: '3px',
    color: '#6B778C',
    lineHeight: 1,
  },
  renameInput: {
    flex: 1,
    border: '1px solid #0052CC',
    borderRadius: '3px',
    padding: '3px 6px',
    fontSize: '13px',
    outline: 'none',
    color: '#172B4D',
  },
  divider: {
    borderTop: '1px solid #F4F5F7',
    margin: '8px 4px',
  },
  createViewBtn: {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    fontSize: '12px',
    color: '#0052CC',
    padding: '6px 12px',
    textAlign: 'left',
    fontWeight: 500,
  },
  newViewForm: {
    display: 'flex',
    alignItems: 'center',
    gap: '4px',
    padding: '4px 8px',
  },
  newViewInput: {
    flex: 1,
    border: '1px solid #0052CC',
    borderRadius: '3px',
    padding: '4px 6px',
    fontSize: '12px',
    outline: 'none',
    minWidth: 0,
  },
  createConfirmBtn: {
    background: '#0052CC',
    color: '#fff',
    border: 'none',
    borderRadius: '3px',
    padding: '4px 8px',
    cursor: 'pointer',
    fontSize: '11px',
    fontWeight: 600,
    flexShrink: 0,
  },
  createCancelBtn: {
    background: 'none',
    border: '1px solid #DFE1E6',
    borderRadius: '3px',
    padding: '4px 6px',
    cursor: 'pointer',
    fontSize: '11px',
    color: '#6B778C',
    flexShrink: 0,
  },
};
